@using sv_8530ab3a4cb5463c9c8de4361a3c0ec3.Services

<button class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-header-row">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <span class="channel-description">@TruncatedDescription</span>
</button>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..37] + "..."
            : Channel.Description;
}

.channel-item {
    display: flex;
    flex-direction: column;
    align-items: stretch;
    width: 100%;
    padding: 8px 12px;
    border: none;
    background: transparent;
    text-align: left;
    cursor: pointer;
    border-radius: 6px;
    margin-bottom: 2px;
    transition: background-color 0.15s;
    color: #ccc;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.12);
    color: #fff;
}

.channel-header-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.channel-item.active .channel-name {
    color: #fff;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.78rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@using sv_8530ab3a4cb5463c9c8de4361a3c0ec3.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background-color: #2b2d31;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 12px 8px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 6px;
}

.message-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #3f4147;
    background: #313338;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #3f4147;
    border-radius: 8px;
    background: #383a40;
    color: #dcddde;
    padding: 10px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-textarea:focus {
    border-color: #5865f2;
}

.message-textarea::placeholder {
    color: #72767d;
}

.send-button {
    padding: 8px 18px;
    background-color: #5865f2;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background-color 0.15s;
    white-space: nowrap;
}

.send-button:hover:not(:disabled) {
    background-color: #4752c4;
}

.send-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_8530ab3a4cb5463c9c8de4361a3c0ec3.Services

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-content-area">
        <div class="message-header">
            <span class="author">@Message.Author</span>
            <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
        </div>
        <div class="message-body">@Message.Content</div>

        @if (Message.Reactions.Count > 0)
        {
            <div class="reactions-row">
                @foreach (var reaction in Message.Reactions)
                {
                    <button class="reaction-badge" @onclick="() => OnReactionAdded.InvokeAsync((Message.Id, reaction.Emoji))">
                        <span>@reaction.Emoji</span>
                        <span class="reaction-count">@reaction.Users.Count</span>
                    </button>
                }
            </div>
        }

        @if (ReplyCount > 0)
        {
            <button class="thread-link" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
                @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
            </button>
        }
    </div>

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
                💬
            </button>
            <button class="action-btn" title="Add reaction" @onclick="ToggleEmojiPicker">
                😀
            </button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
