toolArgs.file_text:
@using sv_8530ab3a4cb5463c9c8de4361a3c0ec3.Services

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-content-area">
        <div class="message-header">
            <span class="author">@Message.Author</span>
            <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
        </div>
        <div class="message-body">@Message.Content</div>

        @if (Message.Reactions.Count > 0)
        {
            <div class="reactions-row">
                @foreach (var reaction in Message.Reactions)
                {
                    <button class="reaction-badge" @onclick="() => OnReactionAdded.InvokeAsync((Message.Id, reaction.Emoji))">
                        <span>@reaction.Emoji</span>
                        <span class="reaction-count">@reaction.Users.Count</span>
                    </button>
                }
            </div>
        }

        @if (ReplyCount > 0)
        {
            <button class="thread-link" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
                @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
            </button>
        }
    </div>

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
                💬
            </button>
            <button class="action-btn" title="Add reaction" @onclick="ToggleEmojiPicker">
                😀
            </button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool showActions;
    private bool showEmojiPicker;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 172800 => "yesterday",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

