@using sv_8530ab3a4cb5463c9c8de4361a3c0ec3.Services
@inject IJSRuntime JS

<div class="message-list" @ref="scrollContainer" @onscroll="HandleScroll">
    @if (IsLoadingMore)
    {
        <div class="load-more-indicator">Loading older messages...</div>
    }
    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ReplyCount="GetReplyCount(message.Id)"
                     OnReplyClicked="OnReplyClicked"
                     OnReactionAdded="OnReactionAdded" />
    }
</div>

@code {
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference scrollContainer;
    private int previousMessageCount;

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Auto-scroll to bottom when new messages arrive (not when loading older)
        if (Messages.Count > previousMessageCount && !IsLoadingMore)
        {
            await JS.InvokeVoidAsync("eval", "document.querySelector('[b-message-list-scroll]')?.scrollTo(0, document.querySelector('[b-message-list-scroll]')?.scrollHeight)");
        }
        previousMessageCount = Messages.Count;
    }

    private async Task HandleScroll()
    {
        // Trigger load-more when scrolled near the top
        if (!IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }
}

