toolArgs.file_text:
@using sv_8530ab3a4cb5463c9c8de4361a3c0ec3.Services

<div class="thread-panel @(IsOpen ? "open" : "")">
    @if (IsOpen && RootMessage is not null)
    {
        <div class="thread-header">
            <h3>Thread</h3>
            <button class="close-btn" @onclick="OnClose">✕</button>
        </div>

        <div class="thread-root-quote">
            <div class="quote-author">@RootMessage.Author</div>
            <div class="quote-content">@RootMessage.Content</div>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-timestamp">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-body">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonLabel="Reply"
                      OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter] public bool IsOpen { get; set; }
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 172800 => "yesterday",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.thread-panel {
    width: 0;
    height: 100%;
    background-color: #2b2d31;
    border-left: 1px solid #3f4147;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    transition: width 0.2s ease;
}

.thread-panel.open {
    width: 25vw;
    min-width: 280px;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #3f4147;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
}

.close-btn {
    background: none;
    border: none;
    color: #b5bac1;
    font-size: 1.1rem;
    cursor: pointer;
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 4px;
    transition: background-color 0.15s, color 0.15s;
}

.close-btn:hover {
    background-color: rgba(255, 255, 255, 0.1);
    color: #fff;
}

.thread-root-quote {
    padding: 12px 16px;
    border-bottom: 1px solid #3f4147;
    background: rgba(255, 255, 255, 0.02);
    border-left: 3px solid #5865f2;
    margin: 8px 12px;
    border-radius: 0 4px 4px 0;
    flex-shrink: 0;
}

.quote-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.85rem;
    margin-bottom: 2px;
}

.quote-content {
    color: #b5bac1;
    font-size: 0.85rem;
    line-height: 1.3;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.85rem;
}

.reply-timestamp {
    font-size: 0.72rem;
    color: #72767d;
}

.reply-body {
    color: #dcddde;
    font-size: 0.85rem;
    line-height: 1.4;
}

