@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_8530ab3a4cb5463c9c8de4361a3c0ec3.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar-col">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main-col @(threadOpen ? "" : "expanded")">
        <MessageArea Channel="activeChannel"
                     Messages="messages"
                     ThreadReplyCounts="threadReplyCounts"
                     IsLoadingMore="isLoadingMore"
                     OnSendMessage="SendMessage"
                     OnLoadMore="LoadOlderMessages"
                     OnReplyClicked="OpenThread"
                     OnReactionAdded="AddReaction" />
    </div>

    <ThreadPanel IsOpen="threadOpen"
                 RootMessage="threadRootMessage"
                 Replies="threadReplies"
                 OnClose="CloseThread"
                 OnSendReply="SendThreadReply" />
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<Message> threadReplies = [];
    private Dictionary<int, int> threadReplyCounts = [];

    private int activeChannelId;
    private Channel? activeChannel;
    private Message? threadRootMessage;
    private bool threadOpen;
    private bool isLoadingMore;
    private bool hasMoreMessages = true;

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadReplyCounts = [];
        hasMoreMessages = true;

        CloseThreadSync();

        var loaded = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count == PageSize;

        BuildThreadReplyCounts();

        await ChatService.MarkChannelReadAsync(channelId);

        // Update the unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task SendMessage(string content)
    {
        var sent = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(sent);
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messages.Count, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            BuildThreadReplyCounts();
        }
        hasMoreMessages = older.Count == PageSize;
        isLoadingMore = false;
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadOpen = true;
    }

    private void CloseThread()
    {
        CloseThreadSync();
    }

    private void CloseThreadSync()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update reply count
        threadReplyCounts[threadRootMessage.Id] =
            threadReplyCounts.GetValueOrDefault(threadRootMessage.Id) + 1;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Update locally
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private void BuildThreadReplyCounts()
    {
        threadReplyCounts = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    background-color: #313338;
    color: #dcddde;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

.chat-sidebar-col {
    width: 20vw;
    min-width: 200px;
    max-width: 300px;
    flex-shrink: 0;
    height: 100%;
}

.chat-main-col {
    flex: 1;
    height: 100%;
    min-width: 0;
    transition: flex 0.2s ease;
}

.chat-main-col.expanded {
    flex: 1;
}

